const https = require('https');

const API_KEY = process.env.HOOKDECK_API_KEY;
const RUN_ID = process.env.ZEALT_RUN_ID;
const API_BASE = 'api.hookdeck.com';

const SOURCE_NAME = `hmac-source-${RUN_ID}`;
const DEST_NAME = `hmac-dest-${RUN_ID}`;
const CONNECTION_NAME = `hmac-connection-${RUN_ID}`;

const HMAC_SECRET_VALUE = 'hmac-secret-key-12345';

const TRANSFORMATION_CODE = `
addHandler("transform", (request, context) => {
  const signature = crypto.createHmac('sha256', env.HMAC_SECRET).update(JSON.stringify(request.body)).digest('hex');
  request.headers['x-hmac-signature'] = signature;
  return request;
});
`.trim();

function makeRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: API_BASE,
      path: path,
      method: method,
      headers: {
        'Authorization': `Bearer ${API_KEY}`,
        'Content-Type': 'application/json',
        'Accept': 'application/json',
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const parsed = JSON.parse(data);
          resolve({ statusCode: res.statusCode, body: parsed });
        } catch (e) {
          resolve({ statusCode: res.statusCode, body: data });
        }
      });
    });

    req.on('error', reject);

    if (body) {
      req.write(JSON.stringify(body));
    }
    req.end();
  });
}

async function main() {
  const fs = require('fs');
  const logLines = [];

  function log(msg) {
    console.log(msg);
    logLines.push(msg);
  }

  // Step 1: Create Source
  log('Creating source...');
  const sourceResp = await makeRequest('POST', '/2024-03-01/sources', {
    name: SOURCE_NAME,
    type: 'WEBHOOK',
  });
  log(`Source response status: ${sourceResp.statusCode}`);

  if (!sourceResp.body.id) {
    log(`Error creating source: ${JSON.stringify(sourceResp.body)}`);
    process.exit(1);
  }

  const sourceId = sourceResp.body.id;
  log(`Source ID: ${sourceId}`);

  // Step 2: Create Destination (MOCK)
  log('Creating destination...');
  const destResp = await makeRequest('POST', '/2024-03-01/destinations', {
    name: DEST_NAME,
    type: 'MOCK_API',
  });
  log(`Destination response status: ${destResp.statusCode}`);

  if (!destResp.body.id) {
    log(`Error creating destination: ${JSON.stringify(destResp.body)}`);
    process.exit(1);
  }

  const destId = destResp.body.id;
  log(`Destination ID: ${destId}`);

  // Step 3: Create Transformation
  log('Creating transformation...');
  const transformResp = await makeRequest('POST', '/2024-03-01/transformations', {
    name: `hmac-transform-${RUN_ID}`,
    code: TRANSFORMATION_CODE,
    env: {
      HMAC_SECRET: HMAC_SECRET_VALUE,
    },
  });
  log(`Transformation response status: ${transformResp.statusCode}`);

  if (!transformResp.body.id) {
    log(`Error creating transformation: ${JSON.stringify(transformResp.body)}`);
    process.exit(1);
  }

  const transformId = transformResp.body.id;
  log(`Transformation ID: ${transformId}`);

  // Step 4: Create Connection
  log('Creating connection...');
  const connectionResp = await makeRequest('POST', '/2024-03-01/connections', {
    name: CONNECTION_NAME,
    source: { id: sourceId },
    destination: { id: destId },
    rules: [
      {
        type: 'transform',
        transformation: { id: transformId },
      },
    ],
  });
  log(`Connection response status: ${connectionResp.statusCode}`);

  if (!connectionResp.body.id) {
    log(`Error creating connection: ${JSON.stringify(connectionResp.body)}`);
    process.exit(1);
  }

  const connectionId = connectionResp.body.id;
  log(`Connection ID: ${connectionId}`);

  // Write output log
  const logContent = logLines.join('\n') + '\n';
  fs.writeFileSync('/home/user/hookdeck-task/output.log', logContent);
  log(`Log written to /home/user/hookdeck-task/output.log`);
}

main().catch((err) => {
  console.error('Fatal error:', err);
  process.exit(1);
});

